// Compliant: Using C++ streams
#include <iostream>
#include <fstream>
#include <string>

void safeFileHandling() {
    std::ifstream file("data.txt");
    std::string line;
    if (file.is_open()) {
        std::getline(file, line);
        file.close();
    }
}

void safeInput() {
    std::string input;
    std::cin >> input; // Safe input handling
    std::cout << "Input: " << input << std::endl;
}
